import { jsx, css } from '@emotion/react';
import { observer } from 'mobx-react';
import { useTheme } from '../../../providers';
import classnames from 'classnames';
import { createImpressionObserver } from '../../../utilities';
const CSS = {
    ResultTracker: () => css({}),
};
export const ResultTracker = observer((properties) => {
    const globalTheme = useTheme();
    const defaultTrack = {
        render: true,
        impression: true,
        click: true,
    };
    const props = {
        // default props
        // global theme
        ...globalTheme?.components?.ResultTracker,
        // props
        ...properties,
        ...properties.theme?.components?.ResultTracker,
    };
    const { children, result, track, controller, className, disableStyles, style } = props;
    const mergedTrack = {
        ...defaultTrack,
        ...track,
    };
    const { ref, inViewport } = createImpressionObserver();
    if (inViewport && mergedTrack.impression) {
        if (result.type === 'product') {
            controller?.track.product.impression(result);
        }
        else {
            // track banner in future
        }
    }
    const styling = {};
    if (!disableStyles) {
        styling.css = [CSS.ResultTracker(), style];
    }
    else if (style) {
        styling.css = [style];
    }
    return (jsx("div", { className: classnames('ss__result-tracker', `ss__${controller?.type}-result-tracker`, className), onClick: (e) => {
            if (result.type === 'product' && mergedTrack.click) {
                controller?.track.product.click(e, result);
            }
        }, ref: ref, ...styling }, children));
});
